logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3 = boto3.client("s3")
sns = boto3.client("sns")

OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET")
OUTPUT_PREFIX = os.environ.get("OUTPUT_PREFIX", "processed/")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")


def build_output_key(input_key: str) -> str:
    filename = input_key.split("/")[-1]
    return f"{OUTPUT_PREFIX}{filename}.json"


def process_image_bytes(image_bytes: bytes, bucket: str, key: str) -> dict:
    return {
        "source_bucket": bucket,
        "source_key": key,
        "size_bytes": len(image_bytes),
        "status": "processed"
    }


def publish_notification(subject: str, message: dict) -> None:
    if not SNS_TOPIC_ARN:
        logger.info("SNS_TOPIC_ARN not set; skipping notification")
        return

    sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject=subject[:100],
        Message=json.dumps(message)
    )


def lambda_handler(event, context):
    logger.info("Received event: %s", json.dumps(event))

    results = []
    failures = []

    records = event.get("Records", [])
    for record in records:
        try:
            if record.get("eventSource") != "aws:s3":
                logger.info("Skipping non-S3 record: %s", json.dumps(record))
                continue

            bucket = record["s3"]["bucket"]["name"]
            key = unquote_plus(record["s3"]["object"]["key"])

            logger.info("Reading object from S3: s3://%s/%s", bucket, key)
            obj = s3.get_object(Bucket=bucket, Key=key)
            image_bytes = obj["Body"].read()

            processed_result = process_image_bytes(image_bytes, bucket, key)

            destination_bucket = OUTPUT_BUCKET or bucket
            destination_key = build_output_key(key)

            logger.info("Writing result to S3: s3://%s/%s", destination_bucket, destination_key)
            s3.put_object(
                Bucket=destination_bucket,
                Key=destination_key,
                Body=json.dumps(processed_result).encode("utf-8"),
                ContentType="application/json"
            )

            notification = {
                "status": "success",
                "input": {"bucket": bucket, "key": key},
                "output": {"bucket": destination_bucket, "key": destination_key},
                "result": processed_result
            }
            publish_notification("Image processed", notification)

            results.append(notification)

        except Exception as e:
            error_info = {
                "status": "failure",
                "error": str(e),
                "traceback": traceback.format_exc(),
                "record": record
            }
            logger.error("Failed processing record: %s", json.dumps(error_info))

            publish_notification("Image processing failed", error_info)
            failures.append(error_info)

    response = {
        "processed_count": len(results),
        "failed_count": len(failures),
        "results": results,
        "failures": failures
    }

    logger.info("Lambda response: %s", json.dumps(response))
    return {
        "statusCode": 200 if not failures else 207,
        "body": json.dumps(response)
    }